```rust
use std::collections::VecDeque;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut adj = vec![vec![]; n];
    let mut in_degree = vec![0; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        in_degree[v] += 1;
    }

    let mut q = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            q.push_back(i as i32);
        }
    }

    let mut topo_order = Vec::new();
    while let Some(u) = q.pop_front() {
        topo_order.push(u);
        for &v in &adj[u as usize] {
            in_degree[v as usize] -= 1;
            if in_degree[v as usize] == 0 {
                q.push_back(v);
            }
        }
    }

    let mut max_edge = 0;
    for edge in &edges {
        let cost = edge[2];
        if cost > max_edge {
            max_edge = cost;
        }
    }

    let mut low = 0;
    let mut high = max_edge;
    let mut ans = -1;

    while low <= high {
        let mid = (low + high) / 2;
        let mut sub_adj = vec![Vec::new(); n];
        for edge in &edges {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            let cost = edge[2];
            if cost >= mid && online[u] && online[v] {
                sub_adj[u].push((v, cost));
            }
        }

        let mut dist = vec![i64::MAX; n];
        dist[0] = 0;
        for u in &topo_order {
            let u_idx = *u as usize;
            if !online[u_idx] {
                continue;
            }
            for (v, cost) in &sub_adj[u_idx] {
                let v_idx = *v;
                if dist[v_idx] > dist[u_idx] + cost {
                    dist[v_idx] = dist[u_idx] + cost;
                }
            }
        }

        if dist[n - 1] <= k {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    ans
}
