from collections import deque

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    # Build adjacency list for topological sort
    adj = [[] for _ in range(n)]
    for u, v, cost in edges:
        adj[u].append(v)

    # Compute topological order using Kahn's algorithm
    in_degree = [0] * n
    for u in range(n):
        for v in adj[u]:
            in_degree[v] += 1

    q = deque()
    for i in range(n):
        if in_degree[i] == 0:
            q.append(i)

    topo_order = []
    while q:
        u = q.popleft()
        topo_order.append(u)
        for v in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Compute max edge cost
    max_edge = 0
    for u, v, cost in edges:
        if cost > max_edge:
            max_edge = cost

    low = 0
    high = max_edge
    ans = -1

    while low <= high:
        mid = (low + high) // 2
        # Build sub_adj for current mid
        sub_adj = [[] for _ in range(n)]
        for u, v, cost in edges:
            if cost < mid:
                continue
            if not online[u]:
                continue
            if not online[v]:
                continue
            sub_adj[u].append((v, cost))

        # DP on topological order
