use std::collections::VecDeque;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    if n == 0 {
        return -1;
    }
    // Build adjacency list for topological sort
    let mut adj = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
    }
    // Compute topological order
    let mut in_degree = vec![0; n];
    for u in 0..n {
        for &v in &adj[u] {
            in_degree[v] += 1;
        }
    }
    let mut q = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            q.push_back(i);
        }
    }
    let mut topo_order = Vec::new();
    while let Some(u) = q.pop_front() {
        topo_order.push(u);
        for &v in &adj[u] {
            in_degree[v] -= 1;
            if in_degree[v] == 0 {
                q.push_back(v);
            }
        }
    }
    // Find max edge cost
    let mut max_edge = 0;
    for edge in &edges {
        let cost = edge[2];
        if cost > max_edge {
            max_edge = cost;
        }
    }
    let mut low = 0;
    let mut high = max_edge;
    let mut ans = -1;
    while low <= high {
        let mid = (low + high) / 2;
        // Build sub_adj
        let mut sub_adj = vec![vec![]; n];
        for edge in &edges {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            let cost = edge[2];
            if cost < mid {
                continue;
            }
            if online[u] && online[v] {
                sub_adj[u].push((v, cost));
            }
        }
        // DP
        let mut dist = vec![i64::MAX; n];
        dist[0] = 0;
        for u in &topo_order {
            if !online[*u] {
                continue;
            }
            for (v, cost) in &sub_adj[*u] {
                if dist[*v] > dist[*u] + *cost {
                    dist[*v] = dist[*u] + *cost;
                }
            }
        }
        if dist[n-1] <= k {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    ans
}
