use std::collections::VecDeque;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    if n == 0 {
        return -1;
    }
    // Build adjacency list for topological sort
    let mut adj_topo = vec![Vec::new(); n];
    let mut in_degree = vec![0; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj_topo[u].push(v);
        in_degree[v] += 1;
    }
    // Compute topological order
    let mut q = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            q.push_back(i as i64);
        }
    }
    let mut topo_order = Vec::new();
    while let Some(u) = q.pop_front() {
        topo_order.push(u);
        for &v in &adj_topo[u as usize] {
            in_degree[v as usize] -= 1;
            if in_degree[v as usize] == 0 {
                q.push_back(v as i64);
            }
        }
    }
    // Build adjacency list for edges with cost
    let mut adj_edges = vec![Vec::new(); n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        adj_edges[u].push( (v, cost) );
    }
    // Find maximum edge cost
    let mut max_cost = 0;
    for edge in &edges {
        let cost = edge[2];
        if cost > max_cost {
            max_cost = cost;
        }
    }
    // Binary search
    let mut low = 0;
    let mut high = max_cost;
    let mut ans = -1;
    while low <= high {
        let mid = (low + high) / 2;
        // Check if possible
        let mut dist = vec![i64::MAX; n];
        dist[0] = 0;
        for u in &topo_order {
            let u_idx = *u as usize;
            if !online[u_idx] {
                continue;
            }
            for (v, cost) in &adj_edges[u_idx] {
                if cost < mid {
                    continue;
                }
                if !online[*v] {
                    continue;
                }
                if dist[*v] > dist[u_idx] + *cost {
                    dist[*v] = dist[u_idx] + *cost;
                }
            }
        }
        if dist[n-1] <= k {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    ans
}

