use std::collections::VecDeque;

fn topological_sort(n: usize, edges: &[Vec<i64>]) -> Vec<i32> {
    let mut adj = vec![vec![]; n];
    let mut in_degree = vec![0; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push((v, edge[2]));
        in_degree[v] += 1;
    }
    let mut q = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            q.push_back(i as i32);
        }
    }
    let mut topo_order = Vec::new();
    while let Some(u) = q.pop_front() {
        topo_order.push(u);
        for (v, _) in &adj[u as usize] {
            let v_idx = *v as usize;
            in_degree[v_idx] -= 1;
            if in_degree[v_idx] == 0 {
                q.push_back(*v);
            }
        }
    }
    topo_order
}

fn can_reach(mid: i64, edges: &[Vec<i64>], online: &[bool], topo_order: &[i32], k: i64, n: usize) -> bool {
    let mut sub_adj = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        if cost < mid {
            continue;
        }
        if online[u] && online[v] {
            sub_adj[u].push((v as i32, cost));
        }
    }
    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;
    for u in topo_order {
        let u_idx = *u as usize;
        if !online[u_idx] {
            continue;
        }
        for (v, cost) in &sub_adj[u_idx] {
            let v_idx = *v as usize;
            if dist[v_idx] > dist[u_idx] + cost {
                dist[v_idx] = dist[u_idx] + cost;
            }
        }
    }
    dist[n - 1] <= k
}

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    if n == 0 {
        return -1;
    }
    let topo_order = topological_sort(n, &edges);
    let mut max_edge = 0;
    for edge in &edges {
        let cost = edge[2];
        if cost > max_edge {
            max_edge = cost;
        }
    }
    let mut low = 0;
    let mut high = max_edge;
    let mut ans = -1;
    while low <= high {
        let mid = (low + high) / 2;
        if can_reach(mid, &edges, &online, &topo_order, k, n) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    ans
}
